// Aggregate the run's results. Emit one alert payload per critical / warning.
const rows = $input.all().map(i => i.json);
if (rows.length === 0) return [{ json: { skipped: true, reason: 'no diagnostic rows' } }];
const run_id = rows[0].run_id;

const critical = rows.filter(r => r.status === 'critical');
const warning  = rows.filter(r => r.status === 'warning');
const ok_count = rows.filter(r => r.status === 'ok').length;

const alerts = [];
for (const r of critical) {
  alerts.push({
    fingerprint: 'diag_' + r.test_id + '_' + run_id.slice(0, 8),
    alertname:   'Diag_' + r.test_id,
    severity:    'critical',
    summary:     'diagnostic critical: ' + r.test_id,
    description: r.detail || ''
  });
}
for (const r of warning) {
  alerts.push({
    fingerprint: 'diag_' + r.test_id + '_' + run_id.slice(0, 8),
    alertname:   'Diag_' + r.test_id,
    severity:    'warning',
    summary:     'diagnostic warning: ' + r.test_id,
    description: r.detail || ''
  });
}

return [{
  json: {
    run_id,
    total: rows.length,
    ok:    ok_count,
    warning: warning.length,
    critical: critical.length,
    alerts_json: JSON.stringify({ alerts: alerts.map(a => ({ ...a, status: 'firing', startsAt: new Date().toISOString(), labels: { alertname: a.alertname, severity: a.severity }, annotations: { summary: a.summary, description: a.description } })) })
  }
}];
